#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) { return (*(int*)a - *(int*)b); }
int main() {
    int T, N;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int arr[N], sorted[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
            sorted[i] = arr[i];
        }
        qsort(sorted, N, sizeof(int), compare);
        int start = -1, end = -1;
        for (int i = 0; i < N; i++) {
            if (arr[i] != sorted[i]) {
                if (start == -1) start = i;
                end = i;
            }
        }
        if (start == -1) printf("0\n");
        else printf("%d\n", end - start + 1);
    }
    return 0;
}

